#!/bin/bash
# Road repeat using exp 59 pipeline (lookahead + detour, tf-based REACH,
# visual anchor matcher, Nav2 planner + pp_follower) and the road-route
# teach data generated by run_teach_single.sh road.
set -eu

E52=/workspace/simulation/isaac/experiments/52_obstacles_v9
E65=/workspace/simulation/isaac/experiments/65_teach_all_routes
SCRIPTS=/workspace/simulation/isaac/scripts
SLAM=/workspace/third_party/ORB_SLAM3
DOMAIN=${ROS_DOMAIN_ID:-85}

TEACH=$E65/teach/road
OUT=${REPEAT_OUT_DIR:-$E65/results/road_repeat}
mkdir -p $OUT

TEACH_MAP=$TEACH/teach_map.yaml
LANDMARKS=$TEACH/landmarks.pkl
TRAJ_CSV=$TEACH/traj_gt.csv
[ -f "$TEACH_MAP" ]  || { echo "ERROR: missing $TEACH_MAP"; exit 1; }
[ -f "$LANDMARKS" ]  || { echo "ERROR: missing $LANDMARKS"; exit 1; }
[ -f "$TRAJ_CSV"  ]  || { echo "ERROR: missing $TRAJ_CSV"; exit 1; }

# v65: also need traj CSV with gt_x,gt_y columns (used by goal sender).
# Our teach writes t,x,y,yaw -> remap headers on a temp copy.
TRAJ_FOR_GOALS=$OUT/traj_gt_for_goals.csv
python3 -c "
import csv
with open('$TRAJ_CSV') as f, open('$TRAJ_FOR_GOALS','w',newline='') as o:
    r = csv.DictReader(f)
    w = csv.writer(o)
    w.writerow(['gt_x','gt_y'])
    for row in r:
        w.writerow([row['x'], row['y']])
print('traj csv remapped for goals sender')
"

pkill -9 -f "run_husky_forest|rgbd_inertial|tf_wall_clock|planner_server|map_server|pure_pursuit_path|send_goals_hybrid|lifecycle_manager|turnaround_supervisor|plan_logger|visual_landmark|ros2 launch" 2>/dev/null || true
sleep 5
rm -rf /dev/shm/fastrtps_* 2>/dev/null
rm -f /tmp/slam_pose.txt /tmp/slam_stop /tmp/slam_status.txt /tmp/isaac_pose.txt /tmp/isaac_imu.txt

echo "=== PHASE 1: Isaac (road + obstacles) + VIO warmup ==="
source /tmp/ros_env.sh 2>/dev/null || true
export RMW_IMPLEMENTATION=rmw_fastrtps_cpp
export ROS_DOMAIN_ID=$DOMAIN

# patch road obstacle positions into spawn_obstacles (no-op here since road
# already defined, but matches exp 52-59 flow):
python3 $E52/scripts/patch_obstacles_exp52.py 2>/dev/null || true

setsid /opt/isaac-sim-6.0.0/python.sh $SCRIPTS/run_husky_forest.py \
    --synthetic-imu --route road --obstacles --duration 1500 \
    </dev/null > $OUT/isaac.log 2>&1 &
ISAAC=$!; disown $ISAAC; echo "Isaac: $ISAAC"

for i in $(seq 1 120); do [ -f /tmp/isaac_pose.txt ] && break; sleep 1; done
sleep 5
REC=$(ls -dt /root/bags/husky_real/isaac_slam_* | head -1)
echo "REC=$REC" > $OUT/run_info.txt

cd $SLAM
setsid ./Examples/RGB-D-Inertial/rgbd_inertial_live \
    Vocabulary/ORBvoc.txt $E65/config/vio_th160.yaml $REC \
    </dev/null > $OUT/vio.log 2>&1 &
VIO=$!; disown $VIO; echo "VIO: $VIO"

cat > /tmp/exp65r_tf_gt.sh <<EOF
#!/bin/bash
source /opt/ros/jazzy/setup.bash
export RMW_IMPLEMENTATION=rmw_fastrtps_cpp
export ROS_DOMAIN_ID=$DOMAIN
export LD_LIBRARY_PATH=\${LD_LIBRARY_PATH:-}:/opt/isaac-sim-6.0.0/exts/isaacsim.ros2.core/jazzy/lib
exec python3 $SCRIPTS/tf_wall_clock_relay.py --use-gt
EOF
chmod +x /tmp/exp65r_tf_gt.sh
nohup bash /tmp/exp65r_tf_gt.sh > $OUT/tf_warmup.log 2>&1 &
TF=$!; disown $TF; echo "TF(GT warmup): $TF"

for i in $(seq 1 300); do
    N=$(head -2 /tmp/slam_pose.txt 2>/dev/null | tail -1 | grep -oP 'frames=\K\d+' || echo 0)
    [ "$N" -ge 200 ] 2>/dev/null && break
    sleep 2
done
echo "VIO warmup: $N frames"

echo "=== PHASE 2: swap to SLAM tf_relay + matcher + Nav2 + PP ==="
touch /tmp/isaac_clear_route.txt
sleep 5
kill $TF 2>/dev/null; sleep 2

cat > /tmp/exp65r_tf_slam.sh <<EOF
#!/bin/bash
source /opt/ros/jazzy/setup.bash
export RMW_IMPLEMENTATION=rmw_fastrtps_cpp
export ROS_DOMAIN_ID=$DOMAIN
export LD_LIBRARY_PATH=\${LD_LIBRARY_PATH:-}:/opt/isaac-sim-6.0.0/exts/isaacsim.ros2.core/jazzy/lib
exec python3 $E65/scripts/tf_wall_clock_relay_v55.py --slam-encoder
EOF
chmod +x /tmp/exp65r_tf_slam.sh
nohup bash /tmp/exp65r_tf_slam.sh > $OUT/tf_slam.log 2>&1 &
TF=$!; disown $TF; echo "TF(SLAM): $TF"
sleep 3

cat > /tmp/exp65r_matcher.sh <<EOF
#!/bin/bash
source /opt/ros/jazzy/setup.bash
export RMW_IMPLEMENTATION=rmw_fastrtps_cpp
export ROS_DOMAIN_ID=$DOMAIN
export LD_LIBRARY_PATH=\${LD_LIBRARY_PATH:-}:/opt/isaac-sim-6.0.0/exts/isaacsim.ros2.core/jazzy/lib
exec python3 $E65/scripts/visual_landmark_matcher.py \
    --landmarks $LANDMARKS --out-csv $OUT/anchor_matches.csv
EOF
chmod +x /tmp/exp65r_matcher.sh
nohup bash /tmp/exp65r_matcher.sh > $OUT/landmark_matcher.log 2>&1 &
MATCHER=$!; disown $MATCHER; echo "Matcher: $MATCHER"

cat > /tmp/exp65r_nav2.sh <<EOF
#!/bin/bash
source /opt/ros/jazzy/setup.bash
export RMW_IMPLEMENTATION=rmw_fastrtps_cpp
export ROS_DOMAIN_ID=$DOMAIN
export LD_LIBRARY_PATH=\${LD_LIBRARY_PATH:-}:/opt/isaac-sim-6.0.0/exts/isaacsim.ros2.core/jazzy/lib
exec ros2 launch $E65/config/nav2_launch_hybrid.py
EOF
chmod +x /tmp/exp65r_nav2.sh
nohup bash /tmp/exp65r_nav2.sh > $OUT/nav2.log 2>&1 &
NAV2=$!; disown $NAV2; echo "Nav2: $NAV2"

cat > /tmp/exp65r_pp.sh <<EOF
#!/bin/bash
source /opt/ros/jazzy/setup.bash
export RMW_IMPLEMENTATION=rmw_fastrtps_cpp
export ROS_DOMAIN_ID=$DOMAIN
export LD_LIBRARY_PATH=\${LD_LIBRARY_PATH:-}:/opt/isaac-sim-6.0.0/exts/isaacsim.ros2.core/jazzy/lib
exec python3 $E65/scripts/pure_pursuit_path_follower.py
EOF
chmod +x /tmp/exp65r_pp.sh
nohup bash /tmp/exp65r_pp.sh > $OUT/pp_follower.log 2>&1 &
PP=$!; disown $PP; echo "PP: $PP"

cat > /tmp/exp65r_sup.sh <<EOF
#!/bin/bash
source /opt/ros/jazzy/setup.bash
export RMW_IMPLEMENTATION=rmw_fastrtps_cpp
export ROS_DOMAIN_ID=$DOMAIN
export LD_LIBRARY_PATH=\${LD_LIBRARY_PATH:-}:/opt/isaac-sim-6.0.0/exts/isaacsim.ros2.core/jazzy/lib
exec python3 $E65/scripts/turnaround_supervisor.py --turnaround-x 45.0 --past-margin 2.0
EOF
chmod +x /tmp/exp65r_sup.sh
nohup bash /tmp/exp65r_sup.sh > $OUT/supervisor.log 2>&1 &
SUP=$!; disown $SUP; echo "Supervisor: $SUP"

cat > /tmp/exp65r_plan.sh <<EOF
#!/bin/bash
source /opt/ros/jazzy/setup.bash
export RMW_IMPLEMENTATION=rmw_fastrtps_cpp
export ROS_DOMAIN_ID=$DOMAIN
export LD_LIBRARY_PATH=\${LD_LIBRARY_PATH:-}:/opt/isaac-sim-6.0.0/exts/isaacsim.ros2.core/jazzy/lib
exec python3 $E65/scripts/plan_logger.py --out-dir $OUT/plans
EOF
mkdir -p $OUT/plans
chmod +x /tmp/exp65r_plan.sh
nohup bash /tmp/exp65r_plan.sh > $OUT/plan_logger.log 2>&1 &
PLN=$!; disown $PLN; echo "PlanLogger: $PLN"

for i in $(seq 1 60); do
    grep -q "Managed nodes are active\|planner_server.*active" $OUT/nav2.log 2>/dev/null && break
    sleep 2
done
echo "Nav2 ready"

echo "=== PHASE 3: Send goals ==="
sleep 3
cat > /tmp/exp65r_goals.sh <<EOF
#!/bin/bash
source /opt/ros/jazzy/setup.bash
export RMW_IMPLEMENTATION=rmw_fastrtps_cpp
export ROS_DOMAIN_ID=$DOMAIN
export LD_LIBRARY_PATH=\${LD_LIBRARY_PATH:-}:/opt/isaac-sim-6.0.0/exts/isaacsim.ros2.core/jazzy/lib
exec python3 $E65/scripts/send_goals_hybrid.py \
    --trajectory $TRAJ_FOR_GOALS --spacing 4.0 --goal-timeout 300 --tolerance 3.0
EOF
chmod +x /tmp/exp65r_goals.sh
nohup bash /tmp/exp65r_goals.sh > $OUT/goals.log 2>&1 &
GOALS=$!; disown $GOALS; echo "Goals: $GOALS"

echo ""
echo "PIDs: Isaac=$ISAAC VIO=$VIO TF=$TF Matcher=$MATCHER Nav2=$NAV2 PP=$PP Sup=$SUP Plan=$PLN Goals=$GOALS"
echo "OUT: $OUT"
